import React, { useState, useEffect } from 'react';
import { Target, Edit2, Save, Trash2, Plus, AlertTriangle } from 'lucide-react';
import { budgetAPI, expenseAPI } from '../../utils/api';
import { useAuth } from '../../context/AuthContext';

const BudgetSettings = () => {
  const { user } = useAuth();
  const [budgets, setBudgets] = useState([]);
  const [spending, setSpending] = useState([]);
  const [allExpenses, setAllExpenses] = useState([]);
  const [editing, setEditing] = useState(null);
  const [editAmount, setEditAmount] = useState('');
  const [newCategory, setNewCategory] = useState('');
  const [newAmount, setNewAmount] = useState('200');
  const [error, setError] = useState('');

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [budgetsData, spendingData, allExpensesData] = await Promise.all([
        budgetAPI.getBudgets(),
        expenseAPI.getSpendingByCategory(),
        expenseAPI.getAll()
      ]);
      
      // Sort alphabetically
      const sorted = [...budgetsData].sort((a, b) => 
        a.category.localeCompare(b.category)
      );
      
      setBudgets(sorted);
      setSpending(spendingData);
      setAllExpenses(allExpensesData);
      setError('');
    } catch (err) {
      console.error('Error loading budget data:', err);
      setError('Failed to load budget data');
    }
  };

  const handleEdit = (category, amount) => {
    setEditing(category);
    setEditAmount(amount.toString());
  };

  const handleSave = async (category) => {
    const value = parseFloat(editAmount);
    if (isNaN(value) || value < 0) {
      setError('Please enter a valid amount');
      return;
    }

    try {
      await budgetAPI.setBudget({ category, amount: value });
      setEditing(null);
      setEditAmount('');
      loadData();
    } catch (err) {
      setError('Failed to save budget');
    }
  };

  const handleAddCategory = async () => {
    const cat = newCategory.trim();
    const amt = parseFloat(newAmount);

    if (!cat) {
      setError('Category name is required');
      return;
    }
    if (isNaN(amt) || amt < 0) {
      setError('Please enter a valid amount');
      return;
    }
    if (budgets.some(b => b.category.toLowerCase() === cat.toLowerCase())) {
      setError('This category already exists');
      return;
    }

    try {
      await budgetAPI.setBudget({ category: cat, amount: amt });
      setNewCategory('');
      setNewAmount('200');
      setError('');
      loadData();
    } catch (err) {
      setError('Failed to create category');
    }
  };

  const handleDelete = async (category) => {
    if (!window.confirm(`Delete budget category "${category}"?`)) return;

    try {
      await budgetAPI.deleteBudget(category);
      loadData();
    } catch (err) {
      setError('Failed to delete category');
    }
  };

  const getColor = (category) => {
    const colors = {
      food: '#3b82f6',
      transport: '#8b5cf6',
      entertainment: '#ec4899',
      shopping: '#f59e0b',
      medicine: '#ef4444',
      other: '#10b981',
    };
    return colors[category.toLowerCase()] || '#6b7280';
  };

  const budgetData = budgets.map(budget => {
    const spent = spending.find(s => s._id?.toLowerCase() === budget.category.toLowerCase())?.total || 0;
    const remaining = budget.amount - spent;
    const percentage = budget.amount > 0 ? (spent / budget.amount) * 100 : 0;
    
    let status = 'normal';
    if (percentage > 100) status = 'over';
    else if (percentage > 85) status = 'warning';
    else if (remaining < 0) status = 'over';

    return {
      category: budget.category,
      budget: budget.amount,
      spent,
      remaining,
      percentage: percentage.toFixed(1),
      color: getColor(budget.category),
      status
    };
  });



  // Overall stats
  const totalBudget = budgets.reduce((sum, b) => sum + b.amount, 0);
  const totalSpent = allExpenses.reduce((sum, exp) => sum + parseFloat(exp.amount || 0), 0);
  const salary = user?.salary || 0;
  const isOverBudget = totalSpent > totalBudget;
  const isOverSalary = totalSpent > salary;

  return (
    <div className="budget-settings p-6 max-w-7xl mx-auto">
      <div className="page-header flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold flex items-center gap-3">
          <Target size={28} /> Budget Settings
        </h1>
      </div>

      {/* Alerts */}
      {(isOverBudget || isOverSalary || error) && (
        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg flex items-start gap-3">
          <AlertTriangle size={20} className="text-red-600 mt-0.5" />
          <div>
            {error && <p className="text-red-700 font-medium">{error}</p>}
            {isOverBudget && <p className="text-red-700">Total spending (${totalSpent.toFixed(2)}) exceeds total budget (${totalBudget.toFixed(2)})</p>}
            {isOverSalary && <p className="text-red-700">Spending exceeds monthly salary (${salary})</p>}
          </div>
        </div>
      )}

      {/* Add new category */}
      <div className="mb-8 p-5 bg-gray-50 border border-gray-200 rounded-xl">
        <h3 className="font-semibold mb-3 flex items-center gap-2">
          <Plus size={18} /> Add New Category
        </h3>
        <div className="flex flex-wrap gap-3">
          <input
            type="text"
            placeholder="Category name (e.g. Bills)"
            value={newCategory}
            onChange={e => setNewCategory(e.target.value)}
            className="flex-1 min-w-[200px] px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
          <input
            type="number"
            placeholder="Budget amount"
            value={newAmount}
            onChange={e => setNewAmount(e.target.value)}
            className="w-36 px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            min="0"
            step="10"
          />
          <button
            onClick={handleAddCategory}
            className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition"
          >
            Add
          </button>
        </div>
      </div>

      {/* Budget cards grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {budgetData.map(item => (
          <div
            key={item.category}
            className="budget-card rounded-xl border shadow-sm overflow-hidden"
            style={{ '--card-color': item.color }}
          >
            <div className="p-5">
              <div className="flex justify-between items-start mb-3">
                <h3 className="text-lg font-semibold capitalize">{item.category}</h3>
                <div className="flex gap-2">
                  {editing === item.category ? (
                    <button
                      onClick={() => handleSave(item.category)}
                      className="p-1.5 text-green-600 hover:bg-green-50 rounded"
                    >
                      <Save size={18} />
                    </button>
                  ) : (
                    <>
                      <button
                        onClick={() => handleEdit(item.category, item.budget)}
                        className="p-1.5 text-blue-600 hover:bg-blue-50 rounded"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button
                        onClick={() => handleDelete(item.category)}
                        className="p-1.5 text-red-600 hover:bg-red-50 rounded"
                      >
                        <Trash2 size={18} />
                      </button>
                    </>
                  )}
                </div>
              </div>

              <div className="mb-4">
                {editing === item.category ? (
                  <input
                    type="number"
                    value={editAmount}
                    onChange={e => setEditAmount(e.target.value)}
                    className="w-full px-3 py-2 border rounded-lg text-xl font-bold focus:outline-none focus:ring-2 focus:ring-blue-500"
                    min="0"
                    step="10"
                  />
                ) : (
                  <div className="text-2xl font-bold text-gray-800">
                    ${item.budget.toFixed(0)}
                  </div>
                )}
              </div>

              <div className="space-y-3">
                <div className="flex justify-between text-sm">
                  <span>Spent:</span>
                  <span className="font-medium">${item.spent.toFixed(2)}</span>
                </div>
                
                <div className="w-full bg-gray-200 rounded-full h-2.5 overflow-hidden">
                  <div
                    className={`h-2.5 rounded-full transition-all duration-500 ${
                      item.status === 'over' ? 'bg-red-500' :
                      item.status === 'warning' ? 'bg-orange-400' : 'bg-green-500'
                    }`}
                    style={{ width: `${Math.min(item.percentage, 100)}%` }}
                  />
                </div>

                <div className="flex justify-between text-sm">
                  <span>Remaining:</span>
                  <span className={`font-medium ${
                    item.remaining < 0 ? 'text-red-600' :
                    item.remaining < item.budget * 0.15 ? 'text-orange-600' : 'text-green-700'
                  }`}>
                    ${item.remaining.toFixed(2)}
                  </span>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default BudgetSettings;
